CREATE TABLE screening_runs(id UUID PRIMARY KEY,customer_id UUID NOT NULL REFERENCES customers(id) ON DELETE CASCADE,subject_type TEXT NOT NULL CHECK(subject_type IN('customer','beneficial_owner')),subject_id UUID NOT NULL,query_name TEXT NOT NULL,provider TEXT NOT NULL,created_by TEXT NOT NULL,created_at TIMESTAMPTZ NOT NULL);
CREATE INDEX screening_runs_customer_created_idx ON screening_runs(customer_id,created_at DESC);
CREATE TABLE screening_matches(id UUID PRIMARY KEY,run_id UUID NOT NULL REFERENCES screening_runs(id) ON DELETE CASCADE,customer_id UUID NOT NULL REFERENCES customers(id) ON DELETE CASCADE,subject_type TEXT NOT NULL,subject_id UUID NOT NULL,query_name TEXT NOT NULL,list_type TEXT NOT NULL CHECK(list_type IN('sanctions','pep','adverse_media')),matched_name TEXT NOT NULL,score INTEGER NOT NULL CHECK(score BETWEEN 0 AND 100),reason TEXT NOT NULL,status TEXT NOT NULL CHECK(status IN('potential','confirmed','false_positive')),created_at TIMESTAMPTZ NOT NULL,reviewed_by TEXT,reviewed_at TIMESTAMPTZ,disposition_reason TEXT);
CREATE INDEX screening_matches_customer_status_idx ON screening_matches(customer_id,status,created_at DESC);
